// IMPORTANT: import only from server code (API route handlers). Never import
// this module from a client component, or the answer key ships to the browser.

// The authoritative answer key, kept out of the client bundle so the timed mock
// is graded on the server and answers cannot be read from the browser.
export interface AnswerOption {
  letter: string;
  text: string;
  correct: boolean;
  explain: string;
}
export interface AnswerQuestion {
  id: string;
  group: string;
  text: string;
  options: AnswerOption[];
}

const encQuestions =
  '';

export const fullQuestions: AnswerQuestion[] = JSON.parse(
  Buffer.from(encQuestions, 'base64').toString('utf8')
);

export const answerKey: Record<string, AnswerQuestion> = Object.fromEntries(
  fullQuestions.map((q) => [q.id, q])
);
